 1	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { LayoutName } from '../../model/topology';
 5	import { Feature, isAllowed } from '../../utils/features-gate';
 6	
 7	export interface LayoutDropdownProps {
 8	  selected: LayoutName;
 9	  setLayout: (l: LayoutName) => void;
10	  id?: string;
11	}
12	
13	export const LayoutDropdown: React.FC<LayoutDropdownProps> = ({ selected, setLayout, id }) => {
14	  const { t } = useTranslation('plugin__netobserv-plugin');
15	  const [isOpen, setOpen] = React.useState(false);
16	
17	  const getLayoutDisplay = (layoutName: LayoutName) => {
18	    switch (layoutName) {
19	      case LayoutName.threeD:
20	        return t('3D');
21	      case LayoutName.breadthFirst:
22	        return t('BreadthFirst');
23	      case LayoutName.cola:
24	        return t('Cola');
25	      case LayoutName.colaGroups:
26	        return t('ColaGroups');
27	      case LayoutName.colaNoForce:
28	        return t('ColaNoForce');
29	      case LayoutName.concentric:
30	        return t('Concentric');
31	      case LayoutName.dagre:
32	        return t('Dagre');
33	      case LayoutName.dagreGroup:
34	        return t('DagreGroup');
35	      case LayoutName.force:
36	        return t('Force');
37	      case LayoutName.grid:
38	        return t('Grid');
39	      default:
40	        return t('Invalid');
41	    }
42	  };
43	
44	  return (
45	    <Dropdown
46	      data-test={id}
47	      id={id}
48	      isOpen={isOpen}
49	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
50	        <MenuToggle
51	          ref={toggleRef}
52	          data-test={`${id}-dropdown`}
53	          id={`${id}-dropdown`}
54	          isExpanded={isOpen}
55	          onClick={() => setOpen(!isOpen)}
56	          onBlur={() => setTimeout(() => setOpen(false), 500)}
57	        >
58	          {getLayoutDisplay(selected)}
59	        </MenuToggle>
60	      )}
61	    >
62	      {Object.values(LayoutName)
63	        .filter(v => v != LayoutName.threeD || isAllowed(Feature.ThreeD))
64	        .map(v => (
65	          <DropdownItem
66	            data-test={v}
67	            id={v}
68	            key={v}
69	            onClick={() => {
70	              setOpen(false);
71	              setLayout(v);
72	            }}
73	          >
74	            {getLayoutDisplay(v)}
75	          </DropdownItem>
76	        ))}
77	    </Dropdown>
78	  );
79	};
80	
81	export default LayoutDropdown;

