 1	import { act, fireEvent, render, screen, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { LayoutName } from '../../../model/topology';
 6	import { LayoutDropdown } from '../layout-dropdown';
 7	
 8	describe('<LayoutDropdown />', () => {
 9	  const props = {
10	    selected: LayoutName.cola,
11	    setLayout: jest.fn(),
12	    id: 'layout'
13	  };
14	
15	  it('should render component', async () => {
16	    render(<LayoutDropdown {...props} />);
17	    expect(screen.getByRole('button')).toHaveAttribute('id', 'layout-dropdown');
18	  });
19	
20	  it('should open and close', async () => {
21	    const { container } = render(<LayoutDropdown {...props} />);
22	
23	    await act(async () => {
24	      fireEvent.click(container.querySelector('#layout-dropdown')!);
25	    });
26	    await waitFor(() => {
27	      expect(document.querySelectorAll('[data-test="layout"] li').length).toBeGreaterThan(0);
28	    });
29	
30	    await act(async () => {
31	      fireEvent.click(container.querySelector('#layout-dropdown')!);
32	    });
33	
34	    expect(props.setLayout).toHaveBeenCalledTimes(0);
35	  });
36	
37	  it('should refresh on select', async () => {
38	    const user = userEvent.setup();
39	    const { container } = render(<LayoutDropdown {...props} />);
40	
41	    await act(async () => {
42	      fireEvent.click(container.querySelector('#layout-dropdown')!);
43	    });
44	    await waitFor(() => expect(document.querySelector('#Dagre')).toBeTruthy());
45	
46	    await user.click(document.querySelector('#Dagre')!);
47	    expect(props.setLayout).toHaveBeenCalledWith(LayoutName.dagre);
48	
49	    await act(async () => {
50	      fireEvent.click(container.querySelector('#layout-dropdown')!);
51	    });
52	    await waitFor(() => expect(document.querySelector('#Force')).toBeTruthy());
53	
54	    await user.click(document.querySelector('#Force')!);
55	
56	    expect(props.setLayout).toHaveBeenCalledTimes(2);
57	    expect(props.setLayout).toHaveBeenCalledWith(LayoutName.force);
58	  });
59	});

